<template><section class="page"><RouterLink to="/evaluations">← {{t('promptops.evaluations.history')}}</RouterLink><p v-if="loading">{{t('promptops.common.loading')}}</p><p v-else-if="error" class="error">{{error}}</p><div v-else-if="!detail" class="empty">{{t('promptops.evaluations.notFound')}}</div><template v-else><header><div><h2>{{t('promptops.evaluations.run')}} {{detail.run.id.slice(0,8)}}</h2><EvaluationStatusBadge :status="detail.run.status"/></div><div><button v-if="active" @click="cancel">{{t('promptops.evaluations.cancel')}}</button><button @click="retry('entire')">{{t('promptops.evaluations.retryEntire')}}</button><button @click="retry('failed')">{{t('promptops.evaluations.retryFailed')}}</button></div></header><section class="card"><h3>{{t('promptops.evaluations.configurationSnapshot')}}</h3><div class="grid"><span>{{detail.run.configSnapshot.dataset.name}}</span><span>{{detail.run.configSnapshot.prompt.name}} · {{detail.run.configSnapshot.promptVersion.versionNumber}}</span><span>{{detail.run.modelConfigKey}}</span><span>{{detail.run.providerId}} / {{detail.run.modelId}}</span><span>T {{detail.run.configSnapshot.temperature}}</span><span>Max {{detail.run.configSnapshot.maxTokens}}</span><span>C {{detail.run.configSnapshot.concurrency}}</span><span>{{detail.run.configSnapshot.pricing.status}}</span></div></section><section class="card"><h3>{{t('promptops.evaluations.progress')}}</h3><progress :value="detail.run.progressPercent??0" max="100"/><div class="grid counters"><span>Total {{detail.run.totalCases}}</span><span>Queued {{detail.run.queuedCases??0}}</span><span>Running {{detail.run.runningCases??0}}</span><span>Succeeded {{detail.run.succeededCases??0}}</span><span>Failed {{detail.run.failedCases??0}}</span><span>Skipped {{detail.run.skippedCases??0}}</span><span>Cancelled {{detail.run.cancelledCases??0}}</span></div></section><section class="card metrics"><h3>{{t('promptops.evaluations.metrics')}}</h3><span>{{t('promptops.evaluations.invocationSuccessRate')}}: {{rate(detail.run.metrics?.invocationSuccessRate)}}</span><span>{{t('promptops.evaluations.validationPassRate')}}: {{rate(detail.run.metrics?.validationPassRate)}}</span><span>{{t('promptops.evaluations.averageLatency')}}: {{number(detail.run.metrics?.averageLatencyMs,'ms')}}</span><span>{{t('promptops.evaluations.totalTokens')}}: {{number(detail.run.metrics?.availableTokenCases?detail.run.metrics.totalTokens:undefined)}}</span><span>{{t('promptops.evaluations.totalCost')}}: {{cost}}</span><span>{{t('promptops.evaluations.averageScore')}}: {{number(detail.run.metrics?.averageDeterministicScore)}}</span></section><div class="filters"><select v-model="resultStatus"><option value="">{{t('promptops.evaluations.allStatuses')}}</option><option v-for="item in resultStatuses" :key="item" :value="item">{{t(`promptops.evaluations.status.${item}`)}}</option></select></div><table><thead><tr><th>{{t('promptops.evaluations.case')}}</th><th>{{t('promptops.evaluations.statusLabel')}}</th><th>{{t('promptops.evaluations.deterministicValidation')}}</th><th>{{t('promptops.evaluations.latency')}}</th><th>{{t('promptops.evaluations.tokens')}}</th><th></th></tr></thead><tbody><tr v-for="item in filtered" :key="item.id"><td>{{item.testCaseSnapshot.name}}</td><td><EvaluationStatusBadge :status="item.status"/></td><td>{{item.deterministicValidation?.score===undefined?'—':`${item.deterministicValidation.passed?'✓':'✕'} ${item.deterministicValidation.score.toFixed(0)}`}}</td><td>{{number(item.latencyMs,'ms')}}</td><td>{{item.tokenUsage.source==='unavailable'?'—':item.tokenUsage.totalTokens}}</td><td><button @click="selected=item">{{t('promptops.actions.view')}}</button></td></tr></tbody></table><div v-if="selected" class="drawer"><button class="close" @click="selected=undefined">×</button><h3>{{selected.testCaseSnapshot.name}}</h3><pre>{{JSON.stringify(selected.testCaseSnapshot,null,2)}}</pre><h4>{{t('promptops.evaluations.output')}}</h4><pre>{{selected.rawOutput??selected.errorMessage}}</pre><h4>{{t('promptops.evaluations.deterministicValidation')}}</h4><div v-for="rule in selected.deterministicValidation?.rules" :key="rule.ruleType+String(rule.expected)"><strong>{{rule.ruleType}} {{rule.passed?'✓':'✕'}}</strong><pre>{{JSON.stringify({expected:rule.expected,actual:rule.actual,diagnostics:rule.diagnostics},null,2)}}</pre></div><RouterLink v-if="selected.invocationId" :to="`/invocations/${selected.invocationId}`">{{t('promptops.evaluations.openInvocation')}}</RouterLink><button @click="retryCase(selected.testCaseId)">{{t('promptops.evaluations.retryCase')}}</button></div></template></section></template>
<script setup lang="ts">import{computed,onBeforeUnmount,ref,watch}from'vue';import{RouterLink,useRoute,useRouter}from'vue-router';import{useI18n}from'vue-i18n';import{EVALUATION_RESULT_STATUSES,type EvaluationResult}from'@prompt-optimizer/core';import{usePromptOpsServices}from'../../services/promptops';import EvaluationStatusBadge from'../../components/promptops/evaluations/EvaluationStatusBadge.vue';const{t}=useI18n(),route=useRoute(),router=useRouter(),services=usePromptOpsServices(),detail=ref<Awaited<ReturnType<typeof services.evaluationQueryService.getDetail>>>(),loading=ref(true),error=ref(''),resultStatus=ref(''),selected=ref<EvaluationResult>(),resultStatuses=EVALUATION_RESULT_STATUSES;let timer:ReturnType<typeof setTimeout>|undefined;const active=computed(()=>detail.value&&['queued','running'].includes(detail.value.run.status)),filtered=computed(()=>detail.value?.results.filter(item=>!resultStatus.value||item.status===resultStatus.value)??[]);const load=async()=>{if(timer)clearTimeout(timer);loading.value=!detail.value;error.value='';try{detail.value=await services.evaluationQueryService.getDetail(String(route.params.evaluationRunId));if(active.value)timer=setTimeout(load,1000)}catch(cause){error.value=cause instanceof Error?cause.message:String(cause)}finally{loading.value=false}};watch(()=>route.params.evaluationRunId,()=>{detail.value=undefined;void load()},{immediate:true});onBeforeUnmount(()=>timer&&clearTimeout(timer));const retry=async(mode:'entire'|'failed')=>{if(!detail.value)return;const run=await services.batchEvaluationService.retry(detail.value.run.id,mode);await router.push(`/evaluations/${run.id}`)};const retryCase=async(id:string)=>{if(!detail.value)return;const run=await services.batchEvaluationService.retry(detail.value.run.id,'case',id);await router.push(`/evaluations/${run.id}`)};const cancel=async()=>{if(detail.value&&confirm(String(t('promptops.evaluations.cancelConfirm')))){await services.batchEvaluationService.cancel(detail.value.run.id);await load()}};const rate=(value?:number)=>value===undefined?'—':`${value.toFixed(1)}%`,number=(value?:number,suffix='')=>value===undefined?'—':`${value.toFixed(1)}${suffix}`,cost=computed(()=>{const metrics=detail.value?.run.metrics;return metrics?.totalCost===undefined?'—':`${metrics.currency} ${metrics.totalCost.toFixed(6)}`})</script>
<style scoped>.page{display:grid;gap:16px}header,.grid,.metrics,.filters{display:flex;gap:12px;align-items:center;flex-wrap:wrap}header{justify-content:space-between}.card{padding:16px;border:1px solid #e2e8f0;border-radius:9px}.grid span,.metrics span{padding:7px;background:#f1f5f9;border-radius:6px}progress{width:100%}table{width:100%;border-collapse:collapse}th,td{text-align:left;padding:9px;border-bottom:1px solid #e2e8f0}.drawer{position:fixed;right:0;top:0;width:min(600px,90vw);height:100vh;overflow:auto;background:white;color:#111827;padding:24px;box-shadow:-4px 0 20px #0003;z-index:50}.close{float:right}.drawer pre{white-space:pre-wrap;background:#f8fafc;padding:10px}.error{color:#b91c1c}.empty{text-align:center;padding:50px}</style>
